def solve(header, rows):
    teams = {}
    for row in rows:
        parts = row.split(',')
        mid, host, guest, hg, gg = parts[0], parts[1], parts[2], int(parts[3]), int(parts[4])
        if host not in teams: teams[host] = [host, 0]
        if guest not in teams: teams[guest] = [guest, 0]
        if hg > gg: teams[host][1] += 3
        elif hg < gg: teams[guest][1] += 3
        else: teams[host][1] += 1; teams[guest][1] += 1
    sorted_teams = sorted(teams.values(), key=lambda x: (-x[1], x[0]))
    return '\n'.join(f"{t[0]},{t[1]}" for t in sorted_teams)

